// --- types.d.ts ---
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

export interface HookReturn {
  formattedTemp: string;
  formattedHumidity: string;
  formattedWind: string;
  weatherIcon: string;
  processedForecast: ForecastDay[];
}

export interface WeatherMainProps {
  city: string;
  temperature: string;
  condition: string;
  icon: string;
}

export interface WeatherStatsProps {
  humidity: string;
  windSpeed: string;
}

export interface ForecastStripProps {
  forecast: ForecastDay[];
  unit: string;
}

export interface ForecastItemProps {
  item: ForecastDay;
  unit: string;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const WEATHER_ICONS: Record<string, string> = {
  'Sunny': '☀️',
  'Cloudy': '☁️',
  'Rainy': '🌧️',
  'Partly Cloudy': '⛅',
  'Stormy': '⛈️',
  'Snowy': '❄️',
  'Clear': '☀️',
  'Mist': '🌫️',
  'Fog': '🌫️',
};

export type UnitType = 'metric' | 'imperial';

interface UnitLabel {
  temperature: string;
  speed: string;
}

export const UNIT_LABELS: Record<UnitType, UnitLabel> = {
  metric: {
    temperature: '°C',
    speed: 'km/h',
  },
  imperial: {
    temperature: '°F',
    speed: 'mph',
  },
};

export const DEFAULT_UNIT: UnitType = 'metric';


// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useMemo } from 'react';
import type { WeatherProps, HookReturn } from './types';

export function useComponent(props: WeatherProps): HookReturn {
  const { temperature, humidity, windSpeed, unit = '°C', condition, forecast } = props;

  const formattedTemp = `${temperature}${unit}`;
  const formattedHumidity = `${humidity}%`;
  const formattedWind = `${windSpeed} km/h`;

  const weatherIcon = useMemo(() => {
    switch (condition) {
      case 'Sunny':
        return '☀️';
      case 'Cloudy':
        return '☁️';
      case 'Rainy':
        return '🌧️';
      case 'Snowy':
        return '❄️';
      case 'Partly Cloudy':
        return '⛅';
      default:
        return '🌡️';
    }
  }, [condition]);

  const processedForecast = useMemo(() => {
    return forecast.slice(0, 5);
  }, [forecast]);

  return {
    formattedTemp,
    formattedHumidity,
    formattedWind,
    weatherIcon,
    processedForecast,
  };
}


// --- components/WeatherMain.tsx ---
import React from 'react';
import { Stack, Heading, Text } from '@ggui-ai/design/primitives';
import { WeatherMainProps } from '../types';

export const WeatherMain: React.FC<WeatherMainProps> = ({
  city,
  temperature,
  condition,
  icon,
}) => {
  return (
    <Stack align="center" gap={12}>
      {/* City Name: Prominent but secondary (Level 2), Neutral 600 */}
      <Heading 
        level={2} 
        color="var(--ggui-color-neutral-600, #4b5563)"
        align="center"
      >
        {city}
      </Heading>

      {/* Temperature and Icon: Alongside, horizontally grouped */}
      <Stack direction="horizontal" align="center" gap={12}>
        {/* Weather Icon: Large font size (3rem) */}
        <Text 
          as="span" 
          style={{ fontSize: '3rem', lineHeight: 1 }}
        >
          {icon}
        </Text>

        {/* Temperature: Largest element, bold, Neutral 900, responsive sizing */}
        <Text
          weight="bold"
          color="var(--ggui-color-neutral-900, #111827)"
          align="center"
          style={{ 
            fontSize: 'clamp(4rem, 12vw, 5.5rem)', 
            lineHeight: 1 
          }}
        >
          {temperature}
        </Text>
      </Stack>

      {/* Condition: Clearly below, size lg, capitalized, Neutral 500 */}
      <Text
        size="lg"
        color="var(--ggui-color-neutral-500, #6b7280)"
        align="center"
        style={{ textTransform: 'capitalize' }}
      >
        {condition}
      </Text>
    </Stack>
  );
};


// --- components/WeatherStats.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { WeatherStatsProps } from '../types';

/**
 * WeatherStats component displays secondary weather metrics (humidity and wind speed)
 * in a side-by-side layout using vertical stacks for each stat.
 */
export const WeatherStats: React.FC<WeatherStatsProps> = ({ humidity, windSpeed }) => {
  return (
    <Stack
      direction="horizontal"
      gap={24}
      justify="center"
      align="center"
    >
      <Stack align="center" gap={4}>
        <Text size="sm" color="var(--ggui-color-neutral-500, #6b7280)">
          💧 Humidity
        </Text>
        <Text weight="medium" color="var(--ggui-color-neutral-900, #111827)">
          {humidity}
        </Text>
      </Stack>
      <Stack align="center" gap={4}>
        <Text size="sm" color="var(--ggui-color-neutral-500, #6b7280)">
          💨 Wind
        </Text>
        <Text weight="medium" color="var(--ggui-color-neutral-900, #111827)">
          {windSpeed}
        </Text>
      </Stack>
    </Stack>
  );
};

export default WeatherStats;


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { ForecastStripProps, ForecastItemProps } from '../types';

/**
 * ForecastItem: Internal sub-component for rendering a single day's forecast.
 */
const ForecastItem: React.FC<ForecastItemProps> = ({ item, unit }) => {
  return (
    <Stack align="center" gap={8} style={{ minWidth: 60, flex: 1 }}>
      {/* Day Label */}
      <Text 
        size="sm" 
        color="var(--ggui-color-neutral-500, #6b7280)" 
        style={{ textTransform: 'uppercase' }}
      >
        {item.day}
      </Text>

      {/* Icon */}
      <Text size="2xl" style={{ lineHeight: 1 }}>
        {item.icon}
      </Text>

      {/* Temperatures */}
      <Stack direction="horizontal" gap={4} align="center">
        <Text weight="bold" size="base">
          {item.high}{unit}
        </Text>
        <Text 
          size="sm" 
          color="var(--ggui-color-neutral-400, #9ca3af)"
        >
          {item.low}{unit}
        </Text>
      </Stack>
    </Stack>
  );
};

/**
 * ForecastStrip: Displays a horizontal sequence of daily weather forecasts.
 */
export const ForecastStrip: React.FC<ForecastStripProps> = ({ forecast, unit }) => {
  // Handle empty or undefined forecast arrays gracefully
  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <Stack
      direction="horizontal"
      justify="between"
      style={{
        overflowX: 'auto',
        WebkitOverflowScrolling: 'touch',
        borderTop: '1px solid var(--ggui-color-neutral-100, #f3f4f6)',
        paddingTop: 'var(--ggui-spacing-4, 16px)',
        gap: 'var(--ggui-spacing-4, 16px)',
      }}
    >
      {forecast.map((item, index) => (
        <ForecastItem key={`${item.day}-${index}`} item={item} unit={unit} />
      ))}
    </Stack>
  );
};

export default ForecastStrip;


// --- ui.tsx ---
import React from 'react';
import { WeatherProps } from './types';
import { useWeather } from './hooks/useWeather';
import { Container, Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { WeatherMain, WeatherStats, ForecastStrip } from './components';

/**
 * WeatherCard Component
 *
 * The main weather dashboard component that displays the current weather,
 * detailed statistics, and a 5-day forecast.
 */
export const WeatherCard: React.FC<WeatherProps> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°C',
  forecast,
}) => {
  // Initialize the useWeather hook with provided weather data
  const {
    formattedTemp,
    formattedHumidity,
    formattedWind,
    weatherIcon,
    processedForecast,
  } = useWeather({
    temperature,
    humidity,
    windSpeed,
    forecast,
    unit,
  });

  return (
    <Container maxWidth="sm">
      <Card shadow="md" padding={16}>
        <Stack direction="vertical" gap={24}>
          {/* Top Section: City and Current Weather */}
          <WeatherMain
            city={city}
            temperature={formattedTemp}
            condition={condition}
            icon={weatherIcon}
          />

          <Divider />

          {/* Middle Section: Humidity and Wind Speed Stats */}
          <WeatherStats
            humidity={formattedHumidity}
            windSpeed={formattedWind}
          />

          <Divider />

          {/* Bottom Section: 5-Day Forecast Strip */}
          <ForecastStrip forecast={processedForecast} unit={unit} />
        </Stack>
      </Card>
    </Container>
  );
};

export default WeatherCard;


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
